  ('fire-eq-tech-moex-02921', 'fire-eq-tech', 'fire-eq-tech-moex-098-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依照「各類場所消防安全設備設置標準」的規定，下列應設置自動撒水設備之規定敘述，何者有誤？', '["8層樓之建築物，供夜總會場所使用之樓層，樓地板面積合計在300平方公尺以上者", "10層樓之建築物，供金融機構場所使用之樓層，樓地板面積在1000平方公尺以上者", "16層的建築物，任一層樓地板面積在100平方公尺以上者", "總樓地板面積在1000平方公尺以上之地下建築物"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "734519161faa", "answer_pdf_sha1": "253922401248", "source_family": "moex-gov-tw", "moex": {"exam_code": "098090", "c": "501", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "098", "exam_name": "098年專技高考引水人、驗船師考試、普考地政士、專責報關人員、保險代理人經紀人及公證人考試、98年第一次消防設備士考試、98年特考中醫師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
